import { useState, useEffect } from 'react'
import { format } from 'date-fns'
import toast from 'react-hot-toast'
import {
  Car,
  Calendar,
  CheckCircle,
  AlertCircle,
  Clock,
  Edit2,
  Save,
  X,
  Search,
  Filter,
  Download,
  Trash2
} from 'lucide-react'

// Indian Rupee formatting function
const formatINR = (amount) => {
  if (amount === null || amount === undefined) return "₹0";
  return new Intl.NumberFormat("en-IN", {
    style: "currency",
    currency: "INR",
    maximumFractionDigits: 0
  }).format(amount);
}

const RepaymentPage = ({ isOpen, onClose, vehicle }) => {
  const [loanHistory, setLoanHistory] = useState([])
  const [loading, setLoading] = useState(true)
  const [searchTerm, setSearchTerm] = useState('')
  const [filterStatus, setFilterStatus] = useState('all')
  const [statistics, setStatistics] = useState(null)
  const [showEditModal, setShowEditModal] = useState(false)
  const [currentEditingEntry, setCurrentEditingEntry] = useState(null)
  const [paymentAmount, setPaymentAmount] = useState('')
  const [paymentMethod, setPaymentMethod] = useState('Bank Transfer')
  const [paymentDate, setPaymentDate] = useState('')
  const [paymentNotes, setPaymentNotes] = useState('')

  useEffect(() => {
    if (isOpen && vehicle) {
      fetchLoanHistory(vehicle._id)
    }
  }, [isOpen, vehicle, filterStatus])

  const fetchLoanHistory = async (vehicleId) => {
    try {
      setLoading(true)
      
      // Fetch all loan history without pagination limit
      const queryParams = new URLSearchParams({
        limit: 1000, // Set a high limit to get all rows
        ...(filterStatus !== 'all' && { status: filterStatus })
      })
      
      const response = await fetch(`/api/loan-history/${vehicleId}?${queryParams}`)
      const data = await response.json()
      
      if (response.ok) {
        setLoanHistory(data.data.loanHistory || [])
        setStatistics(data.data.statistics)
      } else {
        toast.error('Failed to fetch loan history')
      }
    } catch (error) {
      toast.error('Failed to fetch loan history')
    } finally {
      setLoading(false)
    }
  }

  const handlePaymentUpdate = async (loanHistoryId) => {
    try {
      // Create notes with reference number
      const notesWithReference = paymentNotes ? `Reference: ${paymentNotes}` : ''
      
      const response = await fetch(`/api/loan-history/${loanHistoryId}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          paidAmount: parseFloat(paymentAmount),
          paymentMethod,
          paymentDate: paymentDate || new Date().toISOString(),
          notes: notesWithReference
        })
      })
      
      if (response.ok) {
        toast.success('Payment updated successfully')
        setShowEditModal(false)
        setCurrentEditingEntry(null)
        setPaymentAmount('')
        setPaymentMethod('Bank Transfer')
        setPaymentDate('')
        setPaymentNotes('')
        fetchLoanHistory(vehicle._id)
      } else {
        const errorData = await response.json()
        toast.error(errorData.message || 'Failed to update payment')
      }
    } catch (error) {
      toast.error('Failed to update payment')
    }
  }

  const handleDeletePayment = async (loanHistoryId) => {
    if (!confirm('Are you sure you want to delete this payment record?')) {
      return
    }

    try {
      const response = await fetch(`/api/loan-history/${loanHistoryId}`, {
        method: 'DELETE'
      })
      
      if (response.ok) {
        toast.success('Payment record deleted successfully')
        fetchLoanHistory(vehicle._id)
      } else {
        const errorData = await response.json()
        toast.error(errorData.message || 'Failed to delete payment')
      }
    } catch (error) {
      toast.error('Failed to delete payment')
    }
  }

  const getStatusColor = (status) => {
    switch (status) {
      case 'Paid':
        return 'bg-green-100 text-green-800 border-green-200'
      case 'Partial':
        return 'bg-yellow-100 text-yellow-800 border-yellow-200'
      case 'Overdue':
        return 'bg-red-100 text-red-800 border-red-200'
      default:
        return 'bg-gray-100 text-gray-800 border-gray-200'
    }
  }

  const getStatusIcon = (status) => {
    switch (status) {
      case 'Paid':
        return <CheckCircle className="h-4 w-4 text-green-600" />
      case 'Partial':
        return <Clock className="h-4 w-4 text-yellow-600" />
      case 'Overdue':
        return <AlertCircle className="h-4 w-4 text-red-600" />
      default:
        return <Clock className="h-4 w-4 text-gray-600" />
    }
  }

  const getRowColor = (status) => {
    switch (status) {
      case 'Paid':
        return 'bg-green-50 hover:bg-green-100'
      case 'Partial':
        return 'bg-yellow-50 hover:bg-yellow-100'
      case 'Overdue':
        return 'bg-red-50 hover:bg-red-100'
      default:
        return 'bg-white hover:bg-gray-50'
    }
  }

  const exportToExcel = () => {
    if (!vehicle || loanHistory.length === 0) {
      toast.error('No data to export')
      return
    }

    const csvContent = [
      ['No of Due', 'Due Month', 'Loan Amount', 'Due Amount', 'Paid Status', 'Date of Paid', 'Mode of Paid', 'Reference No', 'Remaining Loan Amount'],
      ...loanHistory.map(entry => [
        entry.monthNo,
        format(new Date(entry.dueDate), 'MMM yyyy'),
        formatINR(entry.loanAmount).replace('₹', ''),
        formatINR(entry.dueAmount).replace('₹', ''),
        entry.status,
        entry.paymentDate ? format(new Date(entry.paymentDate), 'dd MMM yyyy') : '-',
        entry.paymentMethod || '-',
        entry.notes ? entry.notes.split('Reference:')[1]?.split('.')[0]?.trim() || '-' : '-',
        formatINR(entry.remainingBalance).replace('₹', '')
      ])
    ].map(row => row.join(',')).join('\n')

    const blob = new Blob([csvContent], { type: 'text/csv' })
    const url = window.URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `repayment-${vehicle.registrationNumber}-${format(new Date(), 'yyyy-MM-dd')}.csv`
    a.click()
    window.URL.revokeObjectURL(url)
    toast.success('Exported to Excel successfully')
  }

  const filteredLoanHistory = loanHistory.filter(entry => {
    const searchLower = searchTerm.toLowerCase()
    return (
      entry.monthNo?.toString().includes(searchLower) ||
      entry.loanNo?.toLowerCase().includes(searchLower) ||
      entry.status?.toLowerCase().includes(searchLower)
    )
  })

  if (!isOpen) return null

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
      <div className="bg-white rounded-xl shadow-xl w-full max-w-6xl mx-4 max-h-[90vh] overflow-hidden">
        {/* Header */}
        <div className="bg-gradient-to-r from-purple-600 to-purple-700 text-white p-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center space-x-3">
              <div className="bg-white bg-opacity-20 rounded p-2">
                <Car className="h-5 w-5 text-white" />
              </div>
              <div>
                <h3 className="text-xl font-bold">Loan Repayment Details</h3>
                <p className="text-purple-100 text-sm">
                  {vehicle?.make} {vehicle?.model} • {vehicle?.registrationNumber}
                </p>
              </div>
            </div>
            <div className="flex items-center space-x-2">
              <button
                onClick={exportToExcel}
                className="flex items-center space-x-1 px-3 py-1 bg-white bg-opacity-20 backdrop-blur-sm rounded hover:bg-opacity-30 transition-colors text-sm"
              >
                <Download className="h-4 w-4" />
                <span>Export</span>
              </button>
              <button
                onClick={onClose}
                className="text-white hover:bg-white hover:bg-opacity-20 rounded p-1 transition-colors"
              >
                <X className="h-4 w-4" />
              </button>
            </div>
          </div>
        </div>

        {/* Statistics */}
        {statistics && (
          <div className="p-3 bg-gray-50 border-b border-gray-200">
            <div className="grid grid-cols-2 md:grid-cols-7 gap-2">
              <div className="bg-white border border-blue-200 rounded-lg shadow-sm p-2">
                <div className="flex items-center justify-between">
                  <Calendar className="h-4 w-4 text-blue-600" />
                  <div className="text-lg font-bold text-blue-900 text-right">{statistics.totalEntries}</div>
                </div>
                <div className="text-xs text-blue-600 text-right">Months</div>
              </div>
              <div className="bg-white border border-green-200 rounded-lg shadow-sm p-2">
                <div className="flex items-center justify-between">
                  <CheckCircle className="h-4 w-4 text-green-600" />
                  <div className="text-lg font-bold text-green-900 text-right">{formatINR(statistics.totalPaid)}</div>
                </div>
                <div className="text-xs text-green-600 text-right">Paid</div>
              </div>
              <div className="bg-white border border-yellow-200 rounded-lg shadow-sm p-2">
                <div className="flex items-center justify-between">
                  <AlertCircle className="h-4 w-4 text-yellow-600" />
                  <div className="text-lg font-bold text-yellow-900 text-right">{formatINR(statistics.remainingBalance)}</div>
                </div>
                <div className="text-xs text-yellow-600 text-right">Remaining</div>
              </div>
              <div className="bg-white border border-purple-200 rounded-lg shadow-sm p-2">
                <div className="flex items-center justify-between">
                  <Clock className="h-4 w-4 text-purple-600" />
                  <div className="text-lg font-bold text-purple-900 text-right">{formatINR(statistics.totalDue)}</div>
                </div>
                <div className="text-xs text-purple-600 text-right">Due</div>
              </div>
              <div className="bg-white border border-green-200 rounded-lg shadow-sm p-2">
                <div className="flex items-center justify-between">
                  <CheckCircle className="h-4 w-4 text-green-600" />
                  <div className="text-lg font-bold text-green-900 text-right">{loanHistory.filter(entry => entry.status === 'Paid').length}</div>
                </div>
                <div className="text-xs text-green-600 text-right">Paid Dues</div>
              </div>
              <div className="bg-white border border-red-200 rounded-lg shadow-sm p-2">
                <div className="flex items-center justify-between">
                  <AlertCircle className="h-4 w-4 text-red-600" />
                  <div className="text-lg font-bold text-red-900 text-right">{loanHistory.filter(entry => entry.status === 'Overdue').length}</div>
                </div>
                <div className="text-xs text-red-600 text-right">Overdues</div>
              </div>
              <div className="bg-white border border-blue-200 rounded-lg shadow-sm p-2">
                <div className="flex items-center justify-between">
                  <Clock className="h-4 w-4 text-blue-600" />
                  <div className="text-lg font-bold text-blue-900 text-right">{loanHistory.filter(entry => entry.status === 'Pending' || entry.status === 'Partial').length}</div>
                </div>
                <div className="text-xs text-blue-600 text-right">Balance Dues</div>
              </div>
            </div>
          </div>
        )}

        {/* Filters */}
        <div className="p-2 bg-white border-b border-gray-200">
          <div className="flex items-center space-x-2 flex-wrap">
            <div className="flex items-center space-x-1">
              <Search className="h-4 w-4 text-gray-600" />
              <span className="text-xs font-medium text-gray-700">Search:</span>
            </div>
            <input
              type="text"
              placeholder="Search..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="px-2 py-1 border border-gray-300 rounded focus:outline-none focus:ring-1 focus:ring-purple-500 text-sm"
            />
            <div className="flex items-center space-x-1">
              <Filter className="h-4 w-4 text-gray-600" />
              <span className="text-xs font-medium text-gray-700">Filter:</span>
            </div>
            <select
              value={filterStatus}
              onChange={(e) => setFilterStatus(e.target.value)}
              className="px-2 py-1 border border-gray-300 rounded focus:outline-none focus:ring-1 focus:ring-purple-500 text-sm"
            >
              <option value="all">All</option>
              <option value="Pending">Pending</option>
              <option value="Paid">Paid</option>
              <option value="Partial">Partial</option>
              <option value="Overdue">Overdue</option>
            </select>
          </div>
        </div>

        {/* Loan History Table */}
        <div className="overflow-x-auto" style={{ maxHeight: '350px', overflowY: 'auto' }}>
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50 sticky top-0 z-10">
              <tr>
                <th className="px-3 py-2 text-left text-xs font-medium text-gray-500 uppercase">Due</th>
                <th className="px-3 py-2 text-left text-xs font-medium text-gray-500 uppercase">Month</th>
                <th className="px-3 py-2 text-right text-xs font-medium text-gray-500 uppercase">Loan</th>
                <th className="px-3 py-2 text-right text-xs font-medium text-gray-500 uppercase">Due</th>
                <th className="px-3 py-2 text-left text-xs font-medium text-gray-500 uppercase">Status</th>
                <th className="px-3 py-2 text-left text-xs font-medium text-gray-500 uppercase">Paid Date</th>
                <th className="px-3 py-2 text-left text-xs font-medium text-gray-500 uppercase">Mode</th>
                <th className="px-3 py-2 text-left text-xs font-medium text-gray-500 uppercase">Ref</th>
                <th className="px-3 py-2 text-right text-xs font-medium text-gray-500 uppercase">Balance</th>
                <th className="px-3 py-2 text-left text-xs font-medium text-gray-500 uppercase">Actions</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {loading ? (
                <tr>
                  <td colSpan="10" className="px-3 py-3 text-center">
                    <div className="flex items-center justify-center">
                      <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-purple-600"></div>
                    </div>
                  </td>
                </tr>
              ) : filteredLoanHistory.length > 0 ? (
                filteredLoanHistory.map((entry) => (
                  <tr key={entry._id} className={getRowColor(entry.status)}>
                    <td className="px-3 py-2 whitespace-nowrap text-sm font-medium text-gray-900">
                      {entry.monthNo}
                    </td>
                    <td className="px-3 py-2 whitespace-nowrap text-sm text-gray-900">
                      {format(new Date(entry.dueDate), 'MMM yyyy')}
                    </td>
                    <td className="px-3 py-2 whitespace-nowrap text-sm font-bold text-gray-900 text-right">
                      {formatINR(entry.loanAmount)}
                    </td>
                    <td className="px-3 py-2 whitespace-nowrap text-sm font-bold text-gray-900 text-right">
                      {formatINR(entry.dueAmount)}
                    </td>
                    <td className="px-3 py-2 whitespace-nowrap">
                      <span className={`inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium border ${getStatusColor(entry.status)}`}>
                        {getStatusIcon(entry.status)}
                        <span className="ml-1">{entry.status}</span>
                      </span>
                    </td>
                    <td className="px-3 py-2 whitespace-nowrap text-sm text-gray-900">
                      {entry.paymentDate ? format(new Date(entry.paymentDate), 'dd MMM yyyy') : '-'}
                    </td>
                    <td className="px-3 py-2 whitespace-nowrap text-sm text-gray-900">
                      {entry.paymentMethod || '-'}
                    </td>
                    <td className="px-3 py-2 whitespace-nowrap text-sm text-gray-900">
                      {entry.notes ? entry.notes.split('Reference:')[1]?.split('.')[0]?.trim() || '-' : '-'}
                    </td>
                    <td className="px-3 py-2 whitespace-nowrap text-sm font-bold text-gray-900 text-right">
                      {formatINR(entry.remainingBalance)}
                    </td>
                    <td className="px-3 py-2 whitespace-nowrap text-sm font-medium">
                      <div className="flex items-center space-x-1">
                        <button
                          onClick={() => {
                            setCurrentEditingEntry(entry)
                            const amountToFill = entry.status === 'Paid' ? entry.paidAmount.toString() : entry.dueAmount.toString()
                            setPaymentAmount(amountToFill)
                            setPaymentMethod(entry.paymentMethod || 'Bank Transfer')
                            setPaymentDate(entry.paymentDate ? new Date(entry.paymentDate).toISOString().split('T')[0] : new Date().toISOString().split('T')[0])
                            setPaymentNotes(entry.notes ? entry.notes.split('Reference:')[1]?.split('.')[0]?.trim() || '' : '')
                            setShowEditModal(true)
                          }}
                          className="text-blue-600 hover:text-blue-900"
                          title="Edit Payment"
                        >
                          <Edit2 className="h-3 w-3" />
                        </button>
                        <button
                          onClick={() => handleDeletePayment(entry._id)}
                          className="text-red-600 hover:text-red-900"
                          title="Delete Payment"
                        >
                          <Trash2 className="h-3 w-3" />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="10" className="px-3 py-3 text-center text-gray-500 text-sm">
                    No loan history found
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>

        {/* Edit Payment Modal */}
        {showEditModal && currentEditingEntry && (
          <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
            <div className="bg-white rounded-lg shadow-lg w-full max-w-sm mx-4">
              <div className="bg-gradient-to-r from-blue-600 to-blue-700 text-white p-3 rounded-t-lg">
                <div className="flex items-center justify-between">
                  <div className="flex items-center space-x-2">
                    <div className="bg-white bg-opacity-20 rounded p-1">
                      <Edit2 className="h-4 w-4 text-white" />
                    </div>
                    <div>
                      <h3 className="text-lg font-bold">Edit Payment</h3>
                      <p className="text-blue-100 text-xs">Month {currentEditingEntry.monthNo} - {format(new Date(currentEditingEntry.dueDate), 'MMM yyyy')}</p>
                    </div>
                  </div>
                  <button
                    onClick={() => {
                      setShowEditModal(false)
                      setCurrentEditingEntry(null)
                      setPaymentAmount('')
                      setPaymentMethod('Bank Transfer')
                      setPaymentDate('')
                      setPaymentNotes('')
                    }}
                    className="text-white hover:bg-white hover:bg-opacity-20 rounded p-1 transition-colors"
                  >
                    <X className="h-4 w-4" />
                  </button>
                </div>
              </div>

              <div className="p-3 space-y-3">
                <div>
                  <label className="block text-xs font-medium text-gray-700 mb-1">
                    Amount *
                  </label>
                  <div className="relative">
                    <span className="absolute left-2 top-1/2 transform -translate-y-1/2 text-gray-500 text-sm">₹</span>
                    <input
                      type="text"
                      value={paymentAmount}
                      onChange={(e) => {
                        const value = e.target.value.replace(/[^0-9]/g, '')
                        setPaymentAmount(value)
                      }}
                      className="w-full pl-6 pr-2 py-1 border border-gray-300 rounded focus:outline-none focus:ring-1 focus:ring-blue-500 bg-blue-50 text-sm"
                      placeholder="0"
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-xs font-medium text-gray-700 mb-1">
                    Date *
                  </label>
                  <div className="relative">
                    <Calendar className="absolute left-2 top-1/2 transform -translate-y-1/2 h-3 w-3 text-gray-400" />
                    <input
                      type="date"
                      value={paymentDate}
                      onChange={(e) => setPaymentDate(e.target.value)}
                      className="w-full pl-7 pr-2 py-1 border border-gray-300 rounded focus:outline-none focus:ring-1 focus:ring-blue-500 text-sm"
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-xs font-medium text-gray-700 mb-1">
                    Method *
                  </label>
                  <select
                    value={paymentMethod}
                    onChange={(e) => setPaymentMethod(e.target.value)}
                    className="w-full px-2 py-1 border border-gray-300 rounded focus:outline-none focus:ring-1 focus:ring-blue-500 text-sm"
                  >
                    <option value="Cash">Cash</option>
                    <option value="Bank Transfer">Bank Transfer</option>
                    <option value="Cheque">Cheque</option>
                    <option value="Online">Online</option>
                    <option value="Auto-debit">Auto-debit</option>
                  </select>
                </div>

                <div>
                  <label className="block text-xs font-medium text-gray-700 mb-1">
                    Reference *
                  </label>
                  <input
                    type="text"
                    value={paymentNotes}
                    onChange={(e) => setPaymentNotes(e.target.value)}
                    className="w-full px-2 py-1 border border-gray-300 rounded focus:outline-none focus:ring-1 focus:ring-blue-500 text-sm"
                    placeholder="Ref number"
                  />
                </div>

                <div className="flex items-center justify-end space-x-2 pt-2 border-t border-gray-200">
                  <button
                    onClick={() => {
                      setShowEditModal(false)
                      setCurrentEditingEntry(null)
                      setPaymentAmount('')
                      setPaymentMethod('Bank Transfer')
                      setPaymentDate('')
                      setPaymentNotes('')
                    }}
                    className="px-3 py-1 text-xs font-medium text-gray-700 bg-gray-100 rounded hover:bg-gray-200"
                  >
                    Cancel
                  </button>
                  <button
                    onClick={() => handlePaymentUpdate(currentEditingEntry._id)}
                    className="px-3 py-1 bg-blue-600 text-white rounded hover:bg-blue-700 flex items-center space-x-1 text-xs"
                  >
                    <Save className="h-3 w-3" />
                    <span>Save</span>
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  )
}

export default RepaymentPage
