import { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { Eye, EyeOff, Lock, User, ArrowRight } from 'lucide-react'

const Login = () => {
  const [formData, setFormData] = useState({
    username: '',
    password: ''
  })
  const [showPassword, setShowPassword] = useState(false)
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState('')
  const [usersData, setUsersData] = useState(null)
  const [showUsers, setShowUsers] = useState(false)
  const navigate = useNavigate()

  const handleIconClick = () => {
    setFormData({
      username: 'saha@gmail.com',
      password: 'saha@gmail.com'
    })
    setError('')
  }

  const fetchUsersData = async () => {
    try {
      console.log('Fetching MongoDB users collection data...')
      const API_BASE_URL = window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1'
        ? 'http://localhost:5001/api'
        : 'https://two026backend.onrender.com/api'
      
      const response = await fetch(`${API_BASE_URL}/users`, {
        method: 'GET',
        headers: {
          'Content-Type': 'application/json',
        }
      })
      
      if (response.ok) {
        const data = await response.json()
        console.log('MongoDB users data:', data)
        setUsersData(data)
        setShowUsers(true)
      } else {
        console.log('Failed to fetch users:', response.status)
        setUsersData({ error: `Failed to fetch users: ${response.status}` })
        setShowUsers(true)
      }
    } catch (error) {
      console.error('Error fetching users:', error)
      setUsersData({ error: `Error: ${error.message}` })
      setShowUsers(true)
    }
  }

  const resetAdminCredentials = (e) => {
    e.preventDefault()
    console.log('Resetting admin credentials...')
    const defaultAdmin = {
      id: 1,
      username: 'admin',
      email: 'admin@example.com',
      password: 'admin123',
      role: 'admin',
      fullName: 'System Administrator',
      phone: '',
      status: 'active',
      createdAt: new Date().toISOString(),
      permissions: {
        dashboard: true,
        customers: true,
        reminders: true,
        billing: true,
        settings: true
      }
    }
    console.log('Admin credentials reset. Use admin/admin123')
    alert('Admin credentials reset! Use admin/admin123 to login.')
  }

  const quickLoginAdmin = (e) => {
    e.preventDefault()
    setFormData({
      username: 'admin',
      password: 'admin123'
    })
    setError('')
  }

  const quickLoginGmail = (e) => {
    e.preventDefault()
    setFormData({
      username: 'g@gmail.com',
      password: 'g@gmail.com'
    })
    setError('')
  }

  const debugUsers = (e) => {
    e.preventDefault() // Prevent form submission
    console.log('=== DEBUG USERS - NOW USING MONGODB ===')
    console.log('Users are now stored in MongoDB database')
    console.log('Check User Management page for all users')
    alert('Users are now stored in MongoDB. Check User Management page.')
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    setIsLoading(true)
    setError('')

    try {
      console.log('=== LOGIN DEBUG ===')
      console.log('Form data:', formData)
      
      // Authenticate against MongoDB users collection
      console.log('Authenticating against MongoDB users database')

      const API_BASE_URL = window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1'
        ? 'http://localhost:5001/api'
        : 'https://two026backend.onrender.com/api'
      
      const response = await fetch(`${API_BASE_URL}/users/auth/login`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          username: formData.username,
          password: formData.password
        })
      })
      
      if (response.ok) {
        const data = await response.json()
        console.log('Login successful with MongoDB user:', data)
        
        // Create user session from MongoDB response
        const userSession = {
          id: data.user.id || data.user._id,
          name: data.user.fullName || data.user.username,
          username: data.user.username,
          email: data.user.email,
          role: data.user.role,
          avatar: data.user.fullName ? data.user.fullName.charAt(0).toUpperCase() : 'U',
          permissions: data.user.permissions || {
            dashboard: true,
            customers: true,
            reminders: true,
            billing: true,
            settings: true
          }
        }
        
        localStorage.setItem('authToken', data.token)
        localStorage.setItem('user', JSON.stringify(userSession))
        console.log('User session saved:', userSession)
        console.log('User data stored in localStorage:', localStorage.getItem('user'))
        
        // Redirect to dashboard
        navigate('/')
      } else {
        const errorData = await response.json().catch(() => ({}))
        throw new Error(errorData.message || 'Authentication failed')
      }
    } catch (err) {
      console.error('Login error:', err)
      setError(err.message || 'Login failed. Please check your credentials.')
    } finally {
      setIsLoading(false)
    }
  }

  const handleInputChange = (e) => {
    const { name, value } = e.target
    setFormData(prev => ({
      ...prev,
      [name]: value
    }))
    if (error) setError('')
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-indigo-900 via-blue-900 to-purple-900 flex items-center justify-center p-4">
      {/* Animated Background Elements */}
      <div className="absolute inset-0 overflow-hidden">
        <div className="absolute -top-40 -right-40 w-96 h-96 bg-gradient-to-br from-indigo-500/20 to-blue-500/20 rounded-full blur-3xl animate-pulse"></div>
        <div className="absolute -bottom-40 -left-40 w-96 h-96 bg-gradient-to-br from-purple-500/20 to-violet-500/20 rounded-full blur-3xl animate-pulse delay-1000"></div>
        <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 w-[600px] h-[600px] bg-gradient-to-br from-blue-500/10 to-indigo-500/10 rounded-full blur-3xl animate-pulse delay-500"></div>
        
        {/* Floating Particles */}
        <div className="absolute top-20 left-20 w-2 h-2 bg-white/30 rounded-full animate-ping"></div>
        <div className="absolute top-40 right-32 w-3 h-3 bg-indigo-400/30 rounded-full animate-ping delay-300"></div>
        <div className="absolute bottom-32 left-40 w-2 h-2 bg-blue-400/30 rounded-full animate-ping delay-700"></div>
        <div className="absolute bottom-20 right-20 w-4 h-4 bg-purple-400/30 rounded-full animate-ping delay-1000"></div>
      </div>

      {/* Login Container */}
      <div className="relative z-10 w-full max-w-md mx-auto">
        <div className="bg-white/10 backdrop-blur-2xl rounded-3xl shadow-2xl overflow-hidden border border-white/20 p-8">
          {/* Logo */}
          <div className="text-center mb-8">
            <h1 className="text-3xl font-bold text-white mb-2">Welcome Back</h1>
            <p className="text-white/70 text-sm">Enter your credentials to access the system</p>
            <div 
              onClick={handleIconClick}
              className="inline-flex items-center justify-center w-16 h-16 bg-gradient-to-br from-indigo-500 to-purple-500 rounded-2xl shadow-lg mt-4 transform hover:scale-110 transition-all duration-300 cursor-pointer active:scale-95"
            >
              <Lock className="h-8 w-8 text-white" />
            </div>
            <p className="text-white/50 text-xs mt-2">Click icon to fill credentials</p>
          </div>

          {/* Error Message */}
          {error && (
            <div className="mb-6 p-4 bg-red-500/20 border border-red-500/30 rounded-lg backdrop-blur">
              <p className="text-sm text-red-200">{error}</p>
            </div>
          )}

          {/* Login Form */}
          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label htmlFor="username" className="block text-sm font-medium text-white/90 mb-2">
                Username
              </label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                  <User className="h-5 w-5 text-white/50" />
                </div>
                <input
                  id="username"
                  name="username"
                  type="text"
                  value={formData.username}
                  onChange={handleInputChange}
                  className="w-full pl-12 pr-4 py-4 bg-white/10 backdrop-blur border border-white/20 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all duration-300 text-white placeholder-white/50 hover:bg-white/15"
                  placeholder="Enter your username"
                  required
                />
              </div>
            </div>

            <div>
              <label htmlFor="password" className="block text-sm font-medium text-white/90 mb-2">
                Password
              </label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                  <Lock className="h-5 w-5 text-white/50" />
                </div>
                <input
                  id="password"
                  name="password"
                  type={showPassword ? 'text' : 'password'}
                  value={formData.password}
                  onChange={handleInputChange}
                  className="w-full pl-12 pr-14 py-4 bg-white/10 backdrop-blur border border-white/20 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all duration-300 text-white placeholder-white/50 hover:bg-white/15"
                  placeholder="Enter your password"
                  required
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute inset-y-0 right-0 pr-4 flex items-center"
                >
                  {showPassword ? (
                    <EyeOff className="h-5 w-5 text-white/50 hover:text-white/70 transition-colors" />
                  ) : (
                    <Eye className="h-5 w-5 text-white/50 hover:text-white/70 transition-colors" />
                  )}
                </button>
              </div>
            </div>

            <div className="flex items-center justify-between">
              <div className="flex items-center">
                <input
                  id="remember"
                  type="checkbox"
                  className="h-4 w-4 text-indigo-600 focus:ring-indigo-500 border-white/30 rounded bg-white/10"
                />
                <label htmlFor="remember" className="ml-2 block text-sm text-white/80">
                  Remember me
                </label>
              </div>
              <a href="#" className="text-sm text-indigo-300 hover:text-indigo-200 transition-colors">
                Forgot password?
              </a>
            </div>

            <button
              type="submit"
              disabled={isLoading}
              className="w-full bg-gradient-to-r from-indigo-500 to-purple-500 text-white py-4 px-6 rounded-xl font-semibold hover:from-indigo-600 hover:to-purple-600 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:ring-offset-2 focus:ring-offset-transparent transition-all duration-300 disabled:opacity-50 disabled:cursor-not-allowed shadow-lg hover:shadow-indigo-500/25 transform hover:-translate-y-0.5 flex items-center justify-center gap-3"
            >
              {isLoading ? (
                <>
                  <svg className="animate-spin h-5 w-5" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Signing in...
                </>
              ) : (
                <>
                  Sign In
                  <ArrowRight className="h-5 w-5" />
                </>
              )}
            </button>

            {/* Quick Actions */}
            <div className="mt-6 space-y-2">
              <div className="text-center text-white/60 text-xs mb-2">Quick Actions:</div>
              <div className="grid grid-cols-2 gap-2">
                <button
                  type="button"
                  onClick={fetchUsersData}
                  className="bg-blue-600/20 border border-blue-500/30 text-blue-300 py-2 px-3 rounded-lg text-xs hover:bg-blue-600/30 transition-colors"
                >
                  Show MongoDB Users
                </button>
                <button
                  type="button"
                  onClick={() => setShowUsers(false)}
                  className="bg-gray-600/20 border border-gray-500/30 text-gray-300 py-2 px-3 rounded-lg text-xs hover:bg-gray-600/30 transition-colors"
                >
                  Hide Users
                </button>
              </div>
            </div>

            {/* MongoDB Users Data Display */}
            {showUsers && usersData && (
              <div className="mt-4 p-4 bg-black/20 border border-white/20 rounded-lg max-h-60 overflow-y-auto">
                <h4 className="text-white text-sm font-semibold mb-2">MongoDB Users Collection:</h4>
                {usersData.error ? (
                  <div className="text-red-300 text-xs">{usersData.error}</div>
                ) : (
                  <div className="text-white text-xs">
                    <div className="mb-2">Total Users: {usersData.count || 0}</div>
                    <pre className="whitespace-pre-wrap text-xs">
                      {JSON.stringify(usersData.data, null, 2)}
                    </pre>
                  </div>
                )}
              </div>
            )}
          </form>
        </div>

        {/* Footer */}
        <div className="text-center mt-8 text-white/60 text-sm">
          <p>&copy; 2026 Vetri. All rights reserved.</p>
        </div>
      </div>
    </div>
  )
}

export default Login
