import React, { useState } from 'react'
import { useSearchParams, useNavigate } from 'react-router-dom'
import Vehicles from './Vehicles.jsx'
import Maintenance from './Maintenance.jsx'
import { Car, Wrench } from 'lucide-react'

const VehicleManagement = () => {
  const navigate = useNavigate()
  const [searchParams] = useSearchParams()
  const activeTab = searchParams.get('tab') || 'vehicles'

  const tabs = [
    { 
      id: 'vehicles', 
      name: 'Add Vehicles', 
      icon: Car, 
      component: Vehicles,
      color: 'blue'
    },
    { 
      id: 'maintenance', 
      name: 'Maintenance', 
      icon: Wrench, 
      component: Maintenance,
      color: 'green'
    }
  ]

  const ActiveComponent = tabs.find(tab => tab.id === activeTab)?.component || Vehicles

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="p-4 sm:p-6 lg:p-8">
        {/* Tab Navigation */}
        <div className="bg-white rounded-lg shadow-sm border border-gray-200 mb-4 sm:mb-8 overflow-hidden">
        <nav className="flex overflow-x-auto overflow-y-hidden">
          {tabs.map((tab) => {
            const Icon = tab.icon
            const isActive = activeTab === tab.id
            const getColorClasses = (color) => {
              switch (color) {
                case 'green':
                  return isActive 
                    ? 'bg-gradient-to-r from-green-500 to-green-600 text-white border-green-500' 
                    : 'text-gray-600 hover:text-green-600 hover:bg-green-50 border-transparent'
                case 'purple':
                  return isActive 
                    ? 'bg-gradient-to-r from-purple-500 to-purple-600 text-white border-purple-500' 
                    : 'text-gray-600 hover:text-purple-600 hover:bg-purple-50 border-transparent'
                default:
                  return isActive 
                    ? 'bg-gradient-to-r from-blue-500 to-blue-600 text-white border-blue-500' 
                    : 'text-gray-600 hover:text-blue-600 hover:bg-blue-50 border-transparent'
              }
            }
            
            return (
              <button
                key={tab.id}
                onClick={() => {
                  navigate(`/vehicle-management?tab=${tab.id}`)
                }}
                className={`flex items-center px-6 py-4 text-sm font-medium border-b-2 transition-all duration-200 whitespace-nowrap ${getColorClasses(tab.color)}`}
              >
                <Icon className="h-4 w-4 mr-2" />
                {tab.name}
              </button>
            )
          })}
        </nav>
      </div>

      {/* Tab Content */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6 min-h-[600px]">
        <ActiveComponent />
      </div>
    </div>
    </div>
  )
}

export default VehicleManagement
