import { useState, useEffect } from 'react'
import { expenseAPI, generalCategoriesAPI } from '../services/settingsAPI'
import { toast } from 'react-hot-toast'
import { formatCurrency } from '../utils/currencyUtils'
import { Plus, Search, Edit2, Trash2, IndianRupee, Calendar, FileText, TrendingUp, TrendingDown, Download, Printer, X, Save } from 'lucide-react'

const ExpenseManagement = () => {
  const [expenses, setExpenses] = useState([])
  const [categories, setCategories] = useState([])
  const [subCategories, setSubCategories] = useState([])
  const [loading, setLoading] = useState(true)
  const [searchTerm, setSearchTerm] = useState('')
  const [showForm, setShowForm] = useState(false)
  const [editingExpense, setEditingExpense] = useState(null)
  const [formData, setFormData] = useState({
    category: '',
    subCategory: '',
    description: '',
    amount: 0,
    date: new Date().toISOString().split('T')[0],
    paymentMethod: 'cash',
    reference: ''
  })

  // Load categories and subcategories
  useEffect(() => {
    const loadData = async () => {
      try {
        setLoading(true)
        
        // Load expense categories
        const categoriesResponse = await expenseAPI.getCategories()
        setCategories(categoriesResponse || [])
        
        // Load expense subcategories
        const subCategoriesResponse = await generalCategoriesAPI.getSubcategories(null, 'expense')
        setSubCategories(subCategoriesResponse || [])
        
        console.log('Expense categories loaded:', categoriesResponse)
        console.log('Expense subcategories loaded:', subCategoriesResponse)
        
        // Load expenses data
        await loadExpenses()
      } catch (error) {
        toast.error('Failed to load expense data')
        console.error('Error loading expense data:', error)
      } finally {
        setLoading(false)
      }
    }
    
    loadData()
  }, [])

  // Listen for expense data changes from other components
  useEffect(() => {
    const handleExpenseDataChanged = (e) => {
      console.log('Expense data changed event received in ExpenseManagement:', e.detail)
      loadExpenses()
    }

    // Listen for custom expense data changes
    window.addEventListener('expenseDataChanged', handleExpenseDataChanged)
    
    // Cleanup listener on unmount
    return () => {
      window.removeEventListener('expenseDataChanged', handleExpenseDataChanged)
    }
  }, [])

  // Refresh data when page becomes visible again (navigation back to page)
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (!document.hidden) {
        console.log('Page became visible, refreshing expense data')
        loadExpenses()
      }
    }

    // Listen for visibility changes
    document.addEventListener('visibilitychange', handleVisibilityChange)
    
    // Cleanup listener on unmount
    return () => {
      document.removeEventListener('visibilitychange', handleVisibilityChange)
    }
  }, [])

  // Get subcategories for selected category
  const getSubCategoriesForCategory = (categoryId) => {
    return subCategories.filter(sub => sub.categoryId === categoryId)
  }

  // Handle form submission
  const handleSubmit = async (e) => {
    e.preventDefault()
    
    // Validate required fields before submission
    if (!formData.category || formData.category === '') {
      toast.error('Please select a category')
      return
    }
    
    if (!formData.amount || formData.amount <= 0) {
      toast.error('Please enter a valid amount')
      return
    }
    
    if (!formData.description || formData.description === '') {
      toast.error('Please enter a description')
      return
    }
    
    try {
      const expenseData = {
        ...formData,
        categoryId: formData.category,
        subCategoryId: formData.subCategory || null, // Allow null for subcategory
        total: parseFloat(formData.amount) || 0,
        date: formData.date,
        description: formData.description,
        paymentMethod: formData.paymentMethod
      }
      
      console.log('Submitting expense data:', expenseData)

      if (editingExpense) {
        await expenseAPI.updateExpense(editingExpense._id, expenseData)
        toast.success('Expense updated successfully')
      } else {
        await expenseAPI.saveExpense(expenseData)
        toast.success('Expense added successfully')
      }
      
      resetForm()
      // Load expenses again to refresh the list
      loadExpenses()
      
      // Trigger custom event to notify other components
      window.dispatchEvent(new CustomEvent('expenseDataChanged', { detail: { action: 'updated' } }))
    } catch (error) {
      toast.error(error.response?.data?.message || error.message || 'Failed to save expense')
      console.error('Error saving expense:', error)
    }
  }

  // Load expenses
  const loadExpenses = async () => {
    try {
      const expensesData = await expenseAPI.getExpenses()
      setExpenses(expensesData || [])
      console.log('Expenses loaded from API:', expensesData)
    } catch (error) {
      console.error('Error loading expenses from API:', error)
      // Fallback to localStorage if API fails
      try {
        const savedExpenses = localStorage.getItem('expenses')
        if (savedExpenses) {
          setExpenses(JSON.parse(savedExpenses))
        }
      } catch (localStorageError) {
        console.error('Error loading expenses from localStorage:', localStorageError)
        setExpenses([])
      }
    }
  }

  // Reset form
  const resetForm = () => {
    setFormData({
      category: '',
      subCategory: '',
      description: '',
      amount: 0,
      date: new Date().toISOString().split('T')[0],
      paymentMethod: 'cash',
      reference: ''
    })
    setEditingExpense(null)
    setShowForm(false)
  }

  // Handle edit
  const handleEdit = (expense) => {
    setEditingExpense(expense)
    setFormData({
      category: expense.categoryId || '',
      subCategory: expense.subCategoryId || '',
      description: expense.description || '',
      amount: expense.amount || 0,
      date: expense.date ? new Date(expense.date).toISOString().split('T')[0] : new Date().toISOString().split('T')[0],
      paymentMethod: expense.paymentMethod || 'cash',
      reference: expense.reference || ''
    })
    setShowForm(true)
  }

  // Handle delete
  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this expense?')) {
      try {
        await expenseAPI.deleteExpense(id)
        // Reload expenses from API
        await loadExpenses()
        toast.success('Expense deleted successfully')
        
        // Trigger custom event to notify other components
        window.dispatchEvent(new CustomEvent('expenseDataChanged', { detail: { action: 'deleted', id } }))
      } catch (error) {
        toast.error('Failed to delete expense')
        console.error('Error deleting expense:', error)
      }
    }
  }

  // Filter expenses
  const filteredExpenses = expenses.filter(expense => {
    const category = categories.find(cat => cat._id === expense.categoryId)
    const subCategory = subCategories.find(sub => sub._id === expense.subCategoryId)
    const categoryName = category ? category.name : ''
    const subCategoryName = subCategory ? subCategory.name : ''
    
    return (
      expense.description.toLowerCase().includes(searchTerm.toLowerCase()) ||
      categoryName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      subCategoryName.toLowerCase().includes(searchTerm.toLowerCase())
    )
  })

  // Calculate totals
  const totalExpenses = expenses.reduce((sum, expense) => sum + (expense.amount || 0), 0)
  const todayExpenses = expenses.filter(expense => {
    const today = new Date().toISOString().split('T')[0]
    return expense.date === today
  }).reduce((sum, expense) => sum + (expense.amount || 0), 0)

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="text-gray-500">Loading expense data...</div>
      </div>
    )
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Expense Management</h1>
          <p className="text-gray-600 mt-1">Track and manage your business expenses</p>
        </div>
        <button
          onClick={() => setShowForm(true)}
          className="flex items-center gap-2 bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-700 transition-colors"
        >
          <Plus className="h-5 w-5" />
          Add Expense
        </button>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-lg shadow-md border border-gray-200">
          <div className="flex items-center">
            <div className="p-3 bg-red-100 rounded-full">
              <TrendingDown className="h-6 w-6 text-red-600" />
            </div>
            <div>
              <p className="text-sm text-gray-600">Total Expenses</p>
              <p className="text-2xl font-bold text-gray-900">₹{totalExpenses.toFixed(2)}</p>
            </div>
          </div>
        </div>
        <div className="bg-white p-6 rounded-lg shadow-md border border-gray-200">
          <div className="flex items-center">
            <div className="p-3 bg-blue-100 rounded-full">
              <Calendar className="h-6 w-6 text-blue-600" />
            </div>
            <div>
              <p className="text-sm text-gray-600">Today's Expenses</p>
              <p className="text-2xl font-bold text-gray-900">₹{todayExpenses.toFixed(2)}</p>
            </div>
          </div>
        </div>
        <div className="bg-white p-6 rounded-lg shadow-md border border-gray-200">
          <div className="flex items-center">
            <div className="p-3 bg-green-100 rounded-full">
              <FileText className="h-6 w-6 text-green-600" />
            </div>
            <div>
              <p className="text-sm text-gray-600">Total Records</p>
              <p className="text-2xl font-bold text-gray-900">{expenses.length}</p>
            </div>
          </div>
        </div>
      </div>

      {/* Search */}
      <div className="bg-white p-4 rounded-lg shadow-md border border-gray-200">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
          <input
            type="text"
            placeholder="Search expenses..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-10 pr-4 py-2 w-full border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          />
        </div>
      </div>

      {/* Expenses Table */}
      <div className="bg-white rounded-lg shadow-md border border-gray-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-gray-50 border-b border-gray-200">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Date</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Category</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Sub Category</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Description</th>
                <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Amount</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Payment</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Actions</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {filteredExpenses.length === 0 ? (
                <tr>
                  <td colSpan="6" className="px-6 py-8 text-center text-gray-500">
                    No expenses found
                  </td>
                </tr>
              ) : (
                filteredExpenses.map((expense) => {
                  const category = categories.find(cat => cat._id === expense.categoryId)
                  const subCategory = subCategories.find(sub => sub._id === expense.subCategoryId)
                  
                  return (
                    <tr key={expense._id} className="hover:bg-gray-50">
                      <td className="px-6 py-4 whitespace-nowrap">
                        <span className="text-sm text-gray-900">{expense.date}</span>
                      </td>
                      <td className="px-6 py-4">
                        <span className="px-2 py-1 text-xs font-medium bg-blue-100 text-blue-800 rounded-full">
                          {category ? category.name : 'N/A'}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <span className="px-2 py-1 text-xs font-medium bg-purple-100 text-purple-800 rounded-full">
                          {subCategory ? subCategory.name : 'N/A'}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <span className="text-sm text-gray-600">{expense.description}</span>
                      </td>
                      <td className="px-6 py-4 text-right font-medium">
                        <span className="text-sm text-gray-900">{formatCurrency(expense.amount)}</span>
                      </td>
                      <td className="px-6 py-4">
                        <span className="px-2 py-1 text-xs font-medium bg-green-100 text-green-800 rounded-full">
                          {expense.paymentMethod || 'Cash'}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center space-x-2">
                          <button
                            onClick={() => handleEdit(expense)}
                            className="text-blue-600 hover:text-blue-900"
                            title="Edit"
                          >
                            <Edit2 className="h-4 w-4" />
                          </button>
                          <button
                            onClick={() => handleDelete(expense._id)}
                            className="text-red-600 hover:text-red-900"
                            title="Delete"
                          >
                            <Trash2 className="h-4 w-4" />
                          </button>
                        </div>
                      </td>
                    </tr>
                  )
                })
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Add/Edit Expense Modal - Bill Format */}
      {showForm && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg shadow-xl w-full max-w-6xl max-h-[90vh] flex flex-col">
            <div className="p-6 border-b border-gray-200 flex-shrink-0">
              <div className="flex justify-between items-center">
                <h2 className="text-2xl font-bold text-gray-800">
                  {editingExpense ? 'Edit Expense' : 'New Expense Bill'}
                </h2>
                <button
                  onClick={() => setShowForm(false)}
                  className="text-gray-500 hover:text-gray-700"
                >
                  <X className="h-6 w-6" />
                </button>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-6">
              {/* Expense Header Information */}
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Expense No</label>
                  <div className="flex items-center gap-2 p-2 border border-gray-300 rounded-lg bg-gray-50">
                    <FileText className="h-4 w-4 text-gray-500" />
                    <input
                      type="text"
                      value={editingExpense ? editingExpense.expenseNo : `EXP-${new Date().getFullYear()}${String(new Date().getMonth() + 1).padStart(2, '0')}${String(new Date().getDate()).padStart(2, '0')}-${Math.floor(Math.random() * 1000).toString().padStart(3, '0')}`}
                      readOnly
                      className="flex-1 bg-transparent outline-none font-mono text-sm"
                    />
                  </div>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Expense Date *</label>
                  <div className="flex items-center gap-2 p-2 border border-gray-300 rounded-lg">
                    <Calendar className="h-4 w-4 text-gray-500" />
                    <input
                      type="date"
                      required
                      value={formData.date}
                      onChange={(e) => setFormData({ ...formData, date: e.target.value })}
                      className="flex-1 outline-none"
                    />
                  </div>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Payment Method</label>
                  <div className="flex items-center gap-2 p-2 border border-gray-300 rounded-lg">
                    <IndianRupee className="h-4 w-4 text-gray-500" />
                    <select
                      value={formData.paymentMethod}
                      onChange={(e) => setFormData({ ...formData, paymentMethod: e.target.value })}
                      className="flex-1 outline-none bg-transparent"
                    >
                      <option value="cash">Cash</option>
                      <option value="card">Card</option>
                      <option value="upi">UPI</option>
                      <option value="bank">Bank Transfer</option>
                      <option value="cheque">Cheque</option>
                    </select>
                  </div>
                </div>
              </div>

              {/* Expense Particulars Table */}
              <div className="mb-6">
                <div className="flex justify-between items-center mb-3">
                  <h3 className="text-lg font-semibold text-gray-800">Expense Particulars</h3>
                </div>

                <div className="overflow-x-auto">
                  <table className="w-full border-collapse border border-gray-300">
                    <thead>
                      <tr className="bg-gray-100">
                        <th className="border border-gray-300 px-3 py-2 text-left text-sm font-medium">S.No</th>
                        <th className="border border-gray-300 px-3 py-2 text-left text-sm font-medium">Category</th>
                        <th className="border border-gray-300 px-3 py-2 text-left text-sm font-medium">Sub Category</th>
                        <th className="border border-gray-300 px-3 py-2 text-left text-sm font-medium">Description</th>
                        <th className="border border-gray-300 px-3 py-2 text-right text-sm font-medium">Amount</th>
                      </tr>
                    </thead>
                    <tbody>
                      <tr>
                        <td className="border border-gray-300 px-3 py-2 text-center">1</td>
                        <td className="border border-gray-300 px-3 py-2">
                          <select
                            required
                            value={formData.category}
                            onChange={(e) => {
                              setFormData({ ...formData, category: e.target.value, subCategory: '' })
                            }}
                            className="w-full border border-gray-200 rounded px-2 py-1 text-sm"
                          >
                            <option value="">Select Category</option>
                            {categories.filter(cat => cat.isActive).map(category => (
                              <option key={category._id} value={category._id}>
                                {category.name}
                              </option>
                            ))}
                          </select>
                        </td>
                        <td className="border border-gray-300 px-3 py-2">
                          <select
                            value={formData.subCategory}
                            onChange={(e) => setFormData({ ...formData, subCategory: e.target.value })}
                            disabled={!formData.category}
                            className="w-full border border-gray-200 rounded px-2 py-1 text-sm disabled:bg-gray-100"
                          >
                            <option value="">Select Sub Category</option>
                            {getSubCategoriesForCategory(formData.category).map(subCategory => (
                              <option key={subCategory._id} value={subCategory._id}>
                                {subCategory.name}
                              </option>
                            ))}
                          </select>
                        </td>
                        <td className="border border-gray-300 px-3 py-2">
                          <textarea
                            required
                            value={formData.description}
                            onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                            className="w-full border border-gray-200 rounded px-2 py-1 text-sm"
                            rows={2}
                            placeholder="Enter expense description"
                          />
                        </td>
                        <td className="border border-gray-300 px-3 py-2">
                          <input
                            type="number"
                            required
                            min="0"
                            step="0.01"
                            value={formData.amount}
                            onChange={(e) => setFormData({ ...formData, amount: parseFloat(e.target.value) || 0 })}
                            className="w-full border border-gray-200 rounded px-2 py-1 text-right text-sm font-medium"
                            placeholder="0.00"
                          />
                        </td>
                      </tr>
                    </tbody>
                  </table>
                </div>
              </div>

              {/* Additional Details and Totals */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                <div>
                  <div className="space-y-3">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Reference Number</label>
                      <input
                        type="text"
                        value={formData.reference}
                        onChange={(e) => setFormData({ ...formData, reference: e.target.value })}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2"
                        placeholder="Enter reference number (optional)"
                      />
                    </div>
                    
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Notes/Remarks</label>
                      <textarea
                        value={formData.notes || ''}
                        onChange={(e) => setFormData({ ...formData, notes: e.target.value })}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2"
                        rows={3}
                        placeholder="Enter any additional notes or remarks"
                      />
                    </div>
                  </div>
                </div>

                <div className="bg-gray-50 rounded-lg p-4">
                  <div className="space-y-2">
                    <div className="flex justify-between">
                      <span className="text-sm text-gray-600">Expense Amount:</span>
                      <span className="font-medium">{formatCurrency(formData.amount)}</span>
                    </div>
                    {formData.paymentMethod !== 'cash' && (
                      <div className="flex justify-between">
                        <span className="text-sm text-gray-600">Transaction Charges:</span>
                        <span className="font-medium">₹0.00</span>
                      </div>
                    )}
                    <div className="border-t pt-2">
                      <div className="flex justify-between">
                        <span className="text-lg font-bold text-gray-800">Total Amount:</span>
                        <span className="text-lg font-bold text-red-600">{formatCurrency(formData.amount)}</span>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              {/* Action Buttons */}
              <div className="border-t border-gray-200 pt-6 flex justify-end gap-3">
                <button
                  type="button"
                  onClick={resetForm}
                  className="px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition-colors"
                >
                  Cancel
                </button>
                <button
                  onClick={handleSubmit}
                  className="flex items-center gap-2 bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-700 transition-colors"
                >
                  <Save className="h-4 w-4" />
                  {editingExpense ? 'Update Expense' : 'Save Expense'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

export default ExpenseManagement
