import React, { useState, useEffect } from 'react'
import { formatCurrency } from '../utils/currencyUtils'
import { useNavigate } from 'react-router-dom'
import { Calendar, TrendingUp, TrendingDown, DollarSign, Building, CreditCard, Plus, Minus, Filter, Download, Search, RefreshCw, ArrowUpRight, ArrowDownRight, Wallet, Banknote, ArrowUpDown } from 'lucide-react'
import { billsAPI, expensesAPI } from '../services/api'
import { toast } from 'react-hot-toast'

const BankingLedger = () => {
  const navigate = useNavigate()
  const [transactions, setTransactions] = useState([])
  const [loading, setLoading] = useState(true)
  const [filterDate, setFilterDate] = useState('')
  const [filterMonth, setFilterMonth] = useState('')
  const [filterYear, setFilterYear] = useState(new Date().getFullYear().toString())
  const [searchTerm, setSearchTerm] = useState('')
  const [currentBalance, setCurrentBalance] = useState(0)
  const [todayBalance, setTodayBalance] = useState(0)
  const [todayIncome, setTodayIncome] = useState(0)
  const [todayExpense, setTodayExpense] = useState(0)
  const [monthBalance, setMonthBalance] = useState(0)
  const [yearBalance, setYearBalance] = useState(0)

  useEffect(() => {
    fetchBankingData()
  }, [filterMonth, filterYear, filterDate, searchTerm])

  const fetchBankingData = async () => {
    try {
      setLoading(true)
      
      // Fetch bills and expenses
      const billsResponse = await billsAPI.getAll()
      const expensesResponse = await expensesAPI.getAll()
      
      const allBills = billsResponse.data || []
      const allExpenses = expensesResponse.data || []
      
      // Process banking transactions
      const bankingTransactions = processBankingTransactions(allBills, allExpenses)
      
      // Apply filters
      const filteredTransactions = filterTransactions(bankingTransactions)
      setTransactions(filteredTransactions)
      
      // Calculate balances
      calculateBalances(bankingTransactions)
    } catch (error) {
      console.error('Error fetching banking data:', error)
      toast.error('Failed to load banking data')
    } finally {
      setLoading(false)
    }
  }

  const processBankingTransactions = (bills, expenses) => {
    const transactions = []
    
    // Process UPI income from bills
    bills.forEach(bill => {
      if (bill.paymentMethod === 'upi') {
        transactions.push({
          id: bill._id,
          type: 'income',
          category: 'UPI Income',
          description: `Bill #${bill.billNo} - ${bill.customerName || 'Customer'}`,
          amount: bill.grandTotal || 0,
          date: bill.billDate || bill.createdAt,
          paymentMethod: 'UPI',
          reference: bill.billNo,
          balance: 0 // Will be calculated later
        })
      }
    })
    
    // Process expenses that affect bank balance
    expenses.forEach(expense => {
      transactions.push({
        id: expense._id,
        type: 'expense',
        category: expense.category || expense.expenseCategory || 'General',
        description: expense.description || expense.name || 'Expense',
        amount: expense.amount || 0,
        date: expense.date || expense.createdAt,
        paymentMethod: expense.paymentMethod || 'cash',
        reference: expense._id,
        balance: 0 // Will be calculated later
      })
    })
    
    // Process balance adjustments from localStorage
    const balanceAdjustments = JSON.parse(localStorage.getItem('bankBalances') || '[]')
    balanceAdjustments.forEach(adjustment => {
      transactions.push({
        id: adjustment.id || adjustment._id,
        type: adjustment.type === 'addition' ? 'income' : 'expense',
        category: adjustment.category || 'Balance Adjustment',
        description: adjustment.description,
        amount: adjustment.amount || 0,
        date: adjustment.date || adjustment.createdAt,
        paymentMethod: adjustment.paymentMethod || 'bank_transfer',
        reference: adjustment.reference || 'Manual',
        accountName: adjustment.accountName || '',
        accountNumber: adjustment.accountNumber || '',
        balance: 0 // Will be calculated later
      })
    })
    
    // Sort by date
    return transactions.sort((a, b) => new Date(b.date) - new Date(a.date))
  }

  const filterTransactions = (transactions) => {
    return transactions.filter(transaction => {
      const transactionDate = new Date(transaction.date)
      
      // Year filter
      if (filterYear && transactionDate.getFullYear().toString() !== filterYear) {
        return false
      }
      
      // Month filter
      if (filterMonth) {
        const transactionMonth = (transactionDate.getMonth() + 1).toString().padStart(2, '0')
        if (transactionMonth !== filterMonth) {
          return false
        }
      }
      
      // Date filter
      if (filterDate) {
        const transactionDateStr = transactionDate.toISOString().split('T')[0]
        if (transactionDateStr !== filterDate) {
          return false
        }
      }
      
      // Search filter
      if (searchTerm) {
        const searchLower = searchTerm.toLowerCase()
        const matchesSearch = 
          transaction.description.toLowerCase().includes(searchLower) ||
          transaction.category.toLowerCase().includes(searchLower) ||
          transaction.paymentMethod.toLowerCase().includes(searchLower) ||
          transaction.reference.toLowerCase().includes(searchLower)
        
        if (!matchesSearch) {
          return false
        }
      }
      
      return true
    })
  }

  const calculateBalances = (allTransactions) => {
    const today = new Date()
    const todayStr = today.toISOString().split('T')[0]
    const currentMonth = today.getMonth()
    const currentYear = today.getFullYear()
    
    let runningBalance = 0
    let todayIncomeTotal = 0
    let todayExpenseTotal = 0
    let todayRunningBalance = 0
    let monthRunningBalance = 0
    let yearRunningBalance = 0
    
    // Calculate balances with running totals
    const transactionsWithBalance = allTransactions.map(transaction => {
      const transactionDate = new Date(transaction.date)
      
      if (transaction.type === 'income') {
        runningBalance += transaction.amount
        
        if (transactionDate.toISOString().split('T')[0] === todayStr) {
          todayIncomeTotal += transaction.amount
          todayRunningBalance += transaction.amount
        }
        
        if (transactionDate.getMonth() === currentMonth && transactionDate.getFullYear() === currentYear) {
          monthRunningBalance += transaction.amount
        }
        
        if (transactionDate.getFullYear() === currentYear) {
          yearRunningBalance += transaction.amount
        }
      } else {
        runningBalance -= transaction.amount
        
        if (transactionDate.toISOString().split('T')[0] === todayStr) {
          todayExpenseTotal += transaction.amount
          todayRunningBalance -= transaction.amount
        }
        
        if (transactionDate.getMonth() === currentMonth && transactionDate.getFullYear() === currentYear) {
          monthRunningBalance -= transaction.amount
        }
        
        if (transactionDate.getFullYear() === currentYear) {
          yearRunningBalance -= transaction.amount
        }
      }
      
      return { ...transaction, balance: runningBalance }
    })
    
    setCurrentBalance(runningBalance)
    setTodayBalance(todayRunningBalance)
    setTodayIncome(todayIncomeTotal)
    setTodayExpense(todayExpenseTotal)
    setMonthBalance(monthRunningBalance)
    setYearBalance(yearRunningBalance)
    
    return transactionsWithBalance
  }

  const clearFilters = () => {
    setFilterDate('')
    setFilterMonth('')
    setFilterYear(new Date().getFullYear().toString())
    setSearchTerm('')
  }

  const exportData = () => {
    const csvContent = generateCSV(transactions)
    downloadCSV(csvContent, 'banking-ledger.csv')
  }

  const generateCSV = (data) => {
    const headers = ['Date', 'Type', 'Category', 'Description', 'Amount', 'Payment Method', 'Reference', 'Balance']
    const rows = data.map(transaction => [
      new Date(transaction.date).toLocaleDateString(),
      transaction.type,
      transaction.category,
      transaction.description,
      transaction.amount,
      transaction.paymentMethod,
      transaction.reference,
      transaction.balance
    ])
    return [headers, ...rows].map(row => row.join(',')).join('\n')
  }

  const downloadCSV = (content, filename) => {
    const blob = new Blob([content], { type: 'text/csv' })
    const url = window.URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = filename
    a.click()
    window.URL.revokeObjectURL(url)
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    )
  }

  return (
    <div className="space-y-6">
      {/* Balance Summary Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
        <div className="relative overflow-hidden rounded-3xl bg-white/10 backdrop-blur-md border border-white/20 shadow-2xl">
          <div className="absolute inset-0 bg-gradient-to-br from-blue-400/20 to-indigo-600/20"></div>
          <div className="relative p-6">
            <div className="flex items-center justify-between mb-4">
              <div className="bg-gradient-to-r from-blue-500 to-indigo-500 rounded-2xl p-3 shadow-xl">
                <Wallet className="h-6 w-6 text-white" />
              </div>
              <div className="bg-blue-500/20 rounded-full px-3 py-1">
                <span className="text-blue-700 text-sm font-semibold">Current</span>
              </div>
            </div>
            <div>
              <p className="text-gray-600 text-sm font-medium mb-2">Current Balance</p>
              <p className="text-3xl font-bold text-gray-900">{formatCurrency(currentBalance)}</p>
              <div className="mt-3 h-2 bg-gradient-to-r from-blue-500 to-indigo-500 rounded-full"></div>
            </div>
          </div>
        </div>

        <div className="relative overflow-hidden rounded-3xl bg-white/10 backdrop-blur-md border border-white/20 shadow-2xl">
          <div className="absolute inset-0 bg-gradient-to-br from-green-400/20 to-emerald-600/20"></div>
          <div className="relative p-6">
            <div className="flex items-center justify-between mb-4">
              <div className="bg-gradient-to-r from-green-500 to-emerald-500 rounded-2xl p-3 shadow-xl">
                <Calendar className="h-6 w-6 text-white" />
              </div>
              <div className="bg-green-500/20 rounded-full px-3 py-1">
                <span className="text-green-700 text-sm font-semibold">Today</span>
              </div>
            </div>
            <div>
              <p className="text-gray-600 text-sm font-medium mb-2">Today's Balance</p>
              <p className="text-3xl font-bold text-gray-900">{formatCurrency(todayBalance)}</p>
              <div className="mt-3 h-2 bg-gradient-to-r from-green-500 to-emerald-500 rounded-full"></div>
            </div>
          </div>
        </div>

        <div className="relative overflow-hidden rounded-3xl bg-white/10 backdrop-blur-md border border-white/20 shadow-2xl">
          <div className="absolute inset-0 bg-gradient-to-br from-purple-400/20 to-pink-600/20"></div>
          <div className="relative p-6">
            <div className="flex items-center justify-between mb-4">
              <div className="bg-gradient-to-r from-purple-500 to-pink-500 rounded-2xl p-3 shadow-xl">
                <TrendingUp className="h-6 w-6 text-white" />
              </div>
              <div className="bg-purple-500/20 rounded-full px-3 py-1">
                <span className="text-purple-700 text-sm font-semibold">Income</span>
              </div>
            </div>
            <div>
              <p className="text-gray-600 text-sm font-medium mb-2">Today's Income</p>
              <p className="text-3xl font-bold text-gray-900">{formatCurrency(todayIncome)}</p>
              <div className="mt-3 h-2 bg-gradient-to-r from-purple-500 to-pink-500 rounded-full"></div>
            </div>
          </div>
        </div>

        <div className="relative overflow-hidden rounded-3xl bg-white/10 backdrop-blur-md border border-white/20 shadow-2xl">
          <div className="absolute inset-0 bg-gradient-to-br from-red-400/20 to-rose-600/20"></div>
          <div className="relative p-6">
            <div className="flex items-center justify-between mb-4">
              <div className="bg-gradient-to-r from-red-500 to-rose-500 rounded-2xl p-3 shadow-xl">
                <TrendingDown className="h-6 w-6 text-white" />
              </div>
              <div className="bg-red-500/20 rounded-full px-3 py-1">
                <span className="text-red-700 text-sm font-semibold">Expense</span>
              </div>
            </div>
            <div>
              <p className="text-gray-600 text-sm font-medium mb-2">Today's Expense</p>
              <p className="text-3xl font-bold text-gray-900">{formatCurrency(todayExpense)}</p>
              <div className="mt-3 h-2 bg-gradient-to-r from-red-500 to-rose-500 rounded-full"></div>
            </div>
          </div>
        </div>

        <div className="relative overflow-hidden rounded-3xl bg-white/10 backdrop-blur-md border border-white/20 shadow-2xl">
          <div className="absolute inset-0 bg-gradient-to-br from-orange-400/20 to-amber-600/20"></div>
          <div className="relative p-6">
            <div className="flex items-center justify-between mb-4">
              <div className="bg-gradient-to-r from-orange-500 to-amber-500 rounded-2xl p-3 shadow-xl">
                <Building className="h-6 w-6 text-white" />
              </div>
              <div className="bg-orange-500/20 rounded-full px-3 py-1">
                <span className="text-orange-700 text-sm font-semibold">Monthly</span>
              </div>
            </div>
            <div>
              <p className="text-gray-600 text-sm font-medium mb-2">Month Balance</p>
              <p className="text-3xl font-bold text-gray-900">{formatCurrency(monthBalance)}</p>
              <div className="mt-3 h-2 bg-gradient-to-r from-orange-500 to-amber-500 rounded-full"></div>
            </div>
          </div>
        </div>
      </div>

      {/* Filters */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
        <div className="flex items-center mb-4">
          <Filter className="h-5 w-5 text-gray-600 mr-2" />
          <h3 className="text-lg font-semibold text-gray-800">Filters</h3>
        </div>
        
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Year</label>
            <select
              value={filterYear}
              onChange={(e) => setFilterYear(e.target.value)}
              className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            >
              <option value="2024">2024</option>
              <option value="2025">2025</option>
              <option value="2026">2026</option>
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Month</label>
            <select
              value={filterMonth}
              onChange={(e) => setFilterMonth(e.target.value)}
              className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            >
              <option value="">All Months</option>
              <option value="01">January</option>
              <option value="02">February</option>
              <option value="03">March</option>
              <option value="04">April</option>
              <option value="05">May</option>
              <option value="06">June</option>
              <option value="07">July</option>
              <option value="08">August</option>
              <option value="09">September</option>
              <option value="10">October</option>
              <option value="11">November</option>
              <option value="12">December</option>
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Date</label>
            <input
              type="date"
              value={filterDate}
              onChange={(e) => setFilterDate(e.target.value)}
              className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Search</label>
            <input
              type="text"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              placeholder="Search transactions..."
              className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
          </div>

          <div className="lg:col-span-3 xl:col-span-5 flex flex-wrap gap-2 items-end">
            <button
              onClick={() => {
                const today = new Date()
                setFilterMonth((today.getMonth() + 1).toString().padStart(2, '0'))
                setFilterYear(today.getFullYear().toString())
                setFilterDate('')
              }}
              className="bg-blue-100 text-blue-700 px-4 py-2 rounded-lg hover:bg-blue-200 transition-colors flex items-center justify-center text-sm font-medium"
            >
              <Calendar className="h-4 w-4 mr-2" />
              This Month
            </button>
            <button
              onClick={() => {
                const today = new Date()
                setFilterMonth('')
                setFilterYear(today.getFullYear().toString())
                setFilterDate('')
              }}
              className="bg-green-100 text-green-700 px-4 py-2 rounded-lg hover:bg-green-200 transition-colors flex items-center justify-center text-sm font-medium"
            >
              <TrendingUp className="h-4 w-4 mr-2" />
              This Year
            </button>
            <button
              onClick={clearFilters}
              className="bg-gray-100 text-gray-700 px-4 py-2 rounded-lg hover:bg-gray-200 transition-colors flex items-center justify-center text-sm font-medium"
            >
              <RefreshCw className="h-4 w-4 mr-2" />
              Clear
            </button>
            <button
              onClick={exportData}
              className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors flex items-center justify-center text-sm font-medium"
            >
              <Download className="h-4 w-4 mr-2" />
              Export
            </button>
          </div>
        </div>
      </div>

      {/* Transactions Table */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200">
        <div className="bg-gradient-to-r from-blue-500 to-indigo-500 p-4">
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-bold text-white flex items-center">
              <Building className="mr-2" />
              Banking Ledger
            </h2>
            <button
              onClick={() => navigate('/add-balance')}
              className="bg-white/20 backdrop-blur-sm text-white px-4 py-2 rounded-lg hover:bg-white/30 transition-colors flex items-center font-medium"
            >
              <Plus className="h-5 w-5 mr-2" />
              Add Balance
            </button>
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full border-collapse">
            <thead>
              <tr className="bg-gradient-to-r from-gray-50 to-gray-100 border-b border-gray-200">
                <th className="border border-gray-200 px-4 py-3 text-left text-sm font-bold text-gray-800">Date</th>
                <th className="border border-gray-200 px-4 py-3 text-left text-sm font-bold text-gray-800">Type</th>
                <th className="border border-gray-200 px-4 py-3 text-left text-sm font-bold text-gray-800">Category</th>
                <th className="border border-gray-200 px-4 py-3 text-left text-sm font-bold text-gray-800">Description</th>
                <th className="border border-gray-200 px-4 py-3 text-left text-sm font-bold text-gray-800">Amount</th>
                <th className="border border-gray-200 px-4 py-3 text-left text-sm font-bold text-gray-800">Payment Method</th>
                <th className="border border-gray-200 px-4 py-3 text-left text-sm font-bold text-gray-800">Account Name</th>
                <th className="border border-gray-200 px-4 py-3 text-left text-sm font-bold text-gray-800">Account Number</th>
                <th className="border border-gray-200 px-4 py-3 text-left text-sm font-bold text-gray-800">Reference</th>
                <th className="border border-gray-200 px-4 py-3 text-left text-sm font-bold text-gray-800">Balance</th>
              </tr>
            </thead>
            <tbody>
              {transactions.map((transaction) => (
                <tr key={transaction.id} className="hover:bg-gray-50">
                  <td className="border border-gray-200 px-4 py-3 text-sm text-gray-600">
                    {new Date(transaction.date).toLocaleDateString()}
                  </td>
                  <td className="border border-gray-200 px-4 py-3 text-sm">
                    <span className={`px-2 py-1 text-xs rounded-full ${
                      transaction.type === 'income' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'
                    }`}>
                      {transaction.type === 'income' ? (
                        <><Plus className="inline h-3 w-3 mr-1" />Income</>
                      ) : (
                        <><Minus className="inline h-3 w-3 mr-1" />Expense</>
                      )}
                    </span>
                  </td>
                  <td className="border border-gray-200 px-4 py-3 text-sm text-gray-600">
                    {transaction.category}
                  </td>
                  <td className="border border-gray-200 px-4 py-3 text-sm text-gray-600">
                    {transaction.description}
                  </td>
                  <td className="border border-gray-200 px-4 py-3 text-sm font-medium">
                    <span className={transaction.type === 'income' ? 'text-green-600' : 'text-red-600'}>
                      {transaction.type === 'income' ? '+' : '-'}{formatCurrency(transaction.amount)}
                    </span>
                  </td>
                  <td className="border border-gray-200 px-4 py-3 text-sm text-gray-600">
                    <span className={`px-2 py-1 text-xs rounded-full ${
                      transaction.paymentMethod === 'upi' ? 'bg-purple-100 text-purple-800' :
                      transaction.paymentMethod === 'cash' ? 'bg-blue-100 text-blue-800' :
                      transaction.paymentMethod === 'credit_card' ? 'bg-green-100 text-green-800' :
                      transaction.paymentMethod === 'bank_transfer' ? 'bg-orange-100 text-orange-800' :
                      'bg-gray-100 text-gray-800'
                    }`}>
                      {transaction.paymentMethod ? transaction.paymentMethod.replace('_', ' ').toUpperCase() : 'N/A'}
                    </span>
                  </td>
                  <td className="border border-gray-200 px-4 py-3 text-sm text-gray-600">
                    {transaction.accountName || '-'}
                  </td>
                  <td className="border border-gray-200 px-4 py-3 text-sm text-gray-600">
                    {transaction.accountNumber || '-'}
                  </td>
                  <td className="border border-gray-200 px-4 py-3 text-sm text-gray-600">
                    {transaction.reference}
                  </td>
                  <td className="border border-gray-200 px-4 py-3 text-sm font-medium text-gray-900">
                    {formatCurrency(transaction.balance)}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {transactions.length === 0 && (
            <div className="p-8 text-center text-gray-500">
              No banking transactions found
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

export default BankingLedger
