import { useState, useEffect } from 'react'
import { format } from 'date-fns'
import toast from 'react-hot-toast'
import { 
  Plus, 
  Edit2, 
  Trash2, 
  Search,
  Filter,
  Printer,
  Calendar,
  FileText,
  Wrench,
  BarChart3,
  AlertTriangle
} from 'lucide-react'
import { machinesAPI } from '../../services/api'
import { useNavigate, useSearchParams } from 'react-router-dom'

const Machines = () => {
  const navigate = useNavigate()
  const [searchParams] = useSearchParams()
  const [machines, setMachines] = useState([])
  const [loading, setLoading] = useState(true)
  const [showModal, setShowModal] = useState(false)
  const [editingMachine, setEditingMachine] = useState(null)
  const [searchTerm, setSearchTerm] = useState('')
  const [filterStatus, setFilterStatus] = useState('')

  const [formData, setFormData] = useState({
    name: '',
    brand: 'Brother',
    modelNumber: '',
    installationDate: '',
    serviceCenterDetails: '',
    warrantyStartDate: '',
    warrantyExpiryDate: '',
    status: 'Active'
  })

  useEffect(() => {
    fetchMachines()
  }, [])

  useEffect(() => {
    const action = searchParams.get('action')
    if (action === 'add') {
      setShowModal(true)
    }
  }, [searchParams])

  const fetchMachines = async () => {
    try {
      const response = await machinesAPI.getAll()
      setMachines(response.data)
    } catch (error) {
      toast.error('Failed to fetch machines')
      console.error('Machines error:', error)
    } finally {
      setLoading(false)
    }
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    try {
      if (editingMachine) {
        await machinesAPI.update(editingMachine._id, formData)
        toast.success('Machine updated successfully')
      } else {
        await machinesAPI.create(formData)
        toast.success('Machine added successfully')
      }
      fetchMachines()
      resetForm()
    } catch (error) {
      toast.error('Failed to save machine')
      console.error('Save machine error:', error)
    }
  }

  const handleEdit = (machine) => {
    setEditingMachine(machine)
    setFormData({
      name: machine.name,
      brand: machine.brand,
      modelNumber: machine.modelNumber,
      installationDate: format(new Date(machine.installationDate), 'yyyy-MM-dd'),
      serviceCenterDetails: machine.serviceCenterDetails || '',
      warrantyStartDate: machine.warrantyStartDate ? format(new Date(machine.warrantyStartDate), 'yyyy-MM-dd') : '',
      warrantyExpiryDate: machine.warrantyExpiryDate ? format(new Date(machine.warrantyExpiryDate), 'yyyy-MM-dd') : '',
      status: machine.status
    })
    setShowModal(true)
  }

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this machine?')) {
      try {
        await machinesAPI.delete(id)
        toast.success('Machine deleted successfully')
        fetchMachines()
      } catch (error) {
        toast.error('Failed to delete machine')
        console.error('Delete machine error:', error)
      }
    }
  }

  const resetForm = () => {
    setFormData({
      name: '',
      brand: 'Brother',
      modelNumber: '',
      installationDate: '',
      serviceCenterDetails: '',
      warrantyStartDate: '',
      warrantyExpiryDate: '',
      status: 'Active'
    })
    setEditingMachine(null)
    setShowModal(false)
  }

  const filteredMachines = machines.filter(machine => {
    const matchesSearch = machine.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         machine.modelNumber.toLowerCase().includes(searchTerm.toLowerCase())
    const matchesFilter = !filterStatus || machine.status === filterStatus
    return matchesSearch && matchesFilter
  })

  const getWarrantyStatus = (warrantyExpiryDate) => {
    if (!warrantyExpiryDate) return null
    
    const today = new Date()
    const expiryDate = new Date(warrantyExpiryDate)
    const daysUntilExpiry = Math.ceil((expiryDate - today) / (1000 * 60 * 60 * 24))
    
    if (daysUntilExpiry < 0) {
      return { status: 'expired', days: Math.abs(daysUntilExpiry), color: 'red' }
    } else if (daysUntilExpiry <= 30) {
      return { status: 'expiring', days: daysUntilExpiry, color: 'orange' }
    } else if (daysUntilExpiry <= 90) {
      return { status: 'warning', days: daysUntilExpiry, color: 'yellow' }
    } else {
      return { status: 'active', days: daysUntilExpiry, color: 'green' }
    }
  }

  const getStatusColor = (status) => {
    switch (status) {
      case 'Active':
        return 'bg-green-100 text-green-800'
      case 'Inactive':
        return 'bg-gray-100 text-gray-800'
      case 'Under Maintenance':
        return 'bg-yellow-100 text-yellow-800'
      default:
        return 'bg-gray-100 text-gray-800'
    }
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    )
  }

  return (
    <div className="h-screen overflow-y-auto space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-gray-900">Machine Management</h2>
        <button
          onClick={() => setShowModal(true)}
          className="btn-primary flex items-center space-x-2"
        >
          <Plus className="h-4 w-4" />
          <span>Add Machine</span>
        </button>
      </div>
 

      {/* Filters */}
      <div className="card">
        <div className="flex flex-col sm:flex-row gap-4">
          <div className="flex-1">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
              <input
                type="text"
                placeholder="Search machines..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-10 w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
              />
            </div>
          </div>
          <div className="flex items-center space-x-2">
            <Filter className="h-4 w-4 text-gray-400" />
            <select
              value={filterStatus}
              onChange={(e) => setFilterStatus(e.target.value)}
              className="px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
            >
              <option value="">All Status</option>
              <option value="Active">Active</option>
              <option value="Inactive">Inactive</option>
              <option value="Under Maintenance">Under Maintenance</option>
            </select>
          </div>
        </div>
      </div>

      {/* Machines Table */}
      <div className="card overflow-hidden">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50 sticky-header">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Brand
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Machine Name
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Model
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Installation Date
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Warranty
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Status
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Actions
                </th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200 table-zebra">
              {filteredMachines.length > 0 ? (
                filteredMachines.map((machine) => (
                  <tr key={machine._id} className="hover:bg-gray-50">
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      {machine.brand}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center">
                        <Printer className="h-5 w-5 text-gray-400 mr-3" />
                        <div className="text-sm font-medium text-gray-900">{machine.name}</div>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      {machine.modelNumber}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      <div className="flex items-center">
                        <Calendar className="h-4 w-4 text-gray-400 mr-2" />
                        {format(new Date(machine.installationDate), 'MMM dd, yyyy')}
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      {getWarrantyStatus(machine.warrantyExpiryDate) ? (
                        <div className="flex items-center space-x-2">
                          {getWarrantyStatus(machine.warrantyExpiryDate).status === 'expired' && (
                            <div className="flex items-center">
                              <AlertTriangle className="h-4 w-4 text-red-500 mr-2" />
                              <span className="text-xs font-semibold px-2 py-1 bg-red-100 text-red-800 rounded-full">
                                Expired {getWarrantyStatus(machine.warrantyExpiryDate).days} days ago
                              </span>
                            </div>
                          )}
                          {getWarrantyStatus(machine.warrantyExpiryDate).status === 'expiring' && (
                            <div className="flex items-center">
                              <AlertTriangle className="h-4 w-4 text-orange-500 mr-2" />
                              <span className="text-xs font-semibold px-2 py-1 bg-orange-100 text-orange-800 rounded-full">
                                {getWarrantyStatus(machine.warrantyExpiryDate).days} days left
                              </span>
                            </div>
                          )}
                          {getWarrantyStatus(machine.warrantyExpiryDate).status === 'warning' && (
                            <div className="flex items-center">
                              <AlertTriangle className="h-4 w-4 text-yellow-500 mr-2" />
                              <span className="text-xs font-semibold px-2 py-1 bg-yellow-100 text-yellow-800 rounded-full">
                                {getWarrantyStatus(machine.warrantyExpiryDate).days} days left
                              </span>
                            </div>
                          )}
                          {getWarrantyStatus(machine.warrantyExpiryDate).status === 'active' && (
                            <span className="text-xs font-semibold px-2 py-1 bg-green-100 text-green-800 rounded-full">
                              {getWarrantyStatus(machine.warrantyExpiryDate).days} days left
                            </span>
                          )}
                        </div>
                      ) : (
                        <span className="text-gray-400 text-xs">No warranty</span>
                      )}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <span className={`px-2 py-1 inline-flex text-xs leading-5 font-semibold rounded-full ${getStatusColor(machine.status)}`}>
                        {machine.status}
                      </span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                      <div className="flex space-x-2">
                        <button
                          onClick={() => handleEdit(machine)}
                          className="text-primary-600 hover:text-primary-900"
                        >
                          <Edit2 className="h-4 w-4" />
                        </button>
                        <button
                          onClick={() => handleDelete(machine._id)}
                          className="text-red-600 hover:text-red-900"
                        >
                          <Trash2 className="h-4 w-4" />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="6" className="px-6 py-4 text-center text-gray-500">
                    No machines found
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Add/Edit Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-gray-600 bg-opacity-50 overflow-y-auto h-full w-full z-50">
          <div className="relative top-20 mx-auto p-5 border w-full max-w-4xl shadow-lg rounded-md bg-white">
            <h3 className="text-lg font-bold text-gray-900 mb-4">
              {editingMachine ? 'Edit Machine' : 'Add New Machine'}
            </h3>
            
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Brand
                  </label>
                  <select
                    value={formData.brand}
                    onChange={(e) => setFormData({ ...formData, brand: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
                  >
                    <option value="Brother">Brother</option>
                    <option value="Canon">Canon</option>
                    <option value="Epson">Epson</option>
                    <option value="HP">HP</option>
                    <option value="Konica Minolta">Konica Minolta</option>
                    <option value="Kyocera">Kyocera</option>
                    <option value="Ricoh">Ricoh</option>
                    <option value="TVS">TVS</option>
                    <option value="Xerox">Xerox</option>
                    <option value="Others">others</option>
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Machine Name
                  </label>
                  <input
                    type="text"
                    required
                    value={formData.name}
                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
                  />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Serial Number
                  </label>
                  <input
                    type="text"
                    required
                    value={formData.modelNumber}
                    onChange={(e) => setFormData({ ...formData, modelNumber: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Installation Date
                  </label>
                  <input
                    type="date"
                    required
                    value={formData.installationDate}
                    onChange={(e) => setFormData({ ...formData, installationDate: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
                  />
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Service Center Details
                </label>
                <textarea
                  value={formData.serviceCenterDetails}
                  onChange={(e) => setFormData({ ...formData, serviceCenterDetails: e.target.value })}
                  rows={2}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
                  placeholder="Enter service center contact information, address, and other details..."
                />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Warranty Start Date
                  </label>
                  <input
                    type="date"
                    value={formData.warrantyStartDate}
                    onChange={(e) => setFormData({ ...formData, warrantyStartDate: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Warranty Expiry Date
                  </label>
                  <input
                    type="date"
                    value={formData.warrantyExpiryDate}
                    onChange={(e) => setFormData({ ...formData, warrantyExpiryDate: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
                  />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Status
                  </label>
                  <select
                    value={formData.status}
                    onChange={(e) => setFormData({ ...formData, status: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
                  >
                    <option value="Active">Active</option>
                    <option value="Inactive">Inactive</option>
                    <option value="Under Maintenance">Under Maintenance</option>
                  </select>
                </div>

                <div className="flex items-end">
                  <div className="w-full"></div>
                </div>
              </div>

              <div className="flex justify-end space-x-3 pt-4">
                <button
                  type="button"
                  onClick={resetForm}
                  className="px-4 py-2 text-sm font-medium text-gray-700 bg-gray-100 rounded-md hover:bg-gray-200"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="btn-primary"
                >
                  {editingMachine ? 'Update' : 'Add'} Machine
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  )
}

export default Machines
